     1→// Phase 5: 타입 시스템 기본 정의
     2→
     3→/**
     4→ * Primitive 타입
     5→ */
     6→export enum PrimitiveType {
     7→  NUM = "num",
     8→  STR = "str",
     9→  BOOL = "bool",
    10→  NULL = "null",
    11→  UNKNOWN = "unknown",
    12→}
    13→
    14→/**
    15→ * 타입 종류
    16→ */
    17→export type Type =
    18→  | { kind: "primitive"; type: PrimitiveType }
    19→  | { kind: "array"; elementType: Type }
    20→  | { kind: "object"; properties: Map<string, Type> }
    21→  | { kind: "fn"; paramTypes: Type[]; returnType: Type; capabilities?: Capability[] }
    22→  | { kind: "union"; types: Type[] }
    23→  | { kind: "never" };
    24→
    25→/**
    26→ * Phase 6: Capability 타입 정의
    27→ */
    28→export type CapabilityKind =
    29→  | "read_file"
    30→  | "write_file"
    31→  | "network"
    32→  | "spawn_process"
    33→  | "execute_code"
    34→
    35→export interface Capability {
    36→  cap: CapabilityKind
    37→  arg?: string
    38→}
    39→
    40→/**
    41→ * 타입 검사 오류
    42→ */
    43→export interface TypeCheckError {
    44→  message: string
    45→  line?: number
    46→  column?: number
    47→  variable?: string
    48→  expected?: Type
    49→  actual?: Type
    50→}
    51→
    52→/**
    53→ * 타입 검사 결과
    54→ */
    55→export interface TypeCheckResult {
    56→  success: boolean
    57→  errors: TypeCheckError[]
    58→  types?: Map<string, Type>
    59→}
    60→
    61→/**
    62→ * 제약 조건
    63→ */
    64→export interface Constraint {
    65→  variable: string
    66→  expectedType: Type
    67→  actualType?: Type
    68→  location?: { line: number; column: number }
    69→}
    70→
    71→/**
    72→ * 충돌 보고서
    73→ */
    74→export interface ConflictReport {
    75→  variable: string
    76→  type1: Type
    77→  type2: Type
    78→  message: string
    79→}
    80→
    81→/**
    82→ * 타입 호환성 확인
    83→ */
    84→export function typesCompatible(type1: Type, type2: Type): boolean {
    85→  // Same type
    86→  if (JSON.stringify(type1) === JSON.stringify(type2)) {
    87→    return true
    88→  }
    89→
    90→  // Unknown type accepts anything (check BEFORE primitive check)
    91→  if (type1.kind === "primitive" && type1.type === PrimitiveType.UNKNOWN) {
    92→    return true
    93→  }
    94→  if (type2.kind === "primitive" && type2.type === PrimitiveType.UNKNOWN) {
    95→    return true
    96→  }
    97→
    98→  // Primitive types
    99→  if (type1.kind === "primitive" && type2.kind === "primitive") {
   100→    return type1.type === type2.type
   101→  }
   102→
   103→  // Array types
   104→  if (type1.kind === "array" && type2.kind === "array") {
   105→    return typesCompatible(type1.elementType, type2.elementType)
   106→  }
   107→
   108→  // Union types - check if type2 is in union
   109→  if (type2.kind === "union") {
   110→    return type2.types.some((t) => typesCompatible(type1, t))
   111→  }
   112→
   113→  return false
   114→}
   115→
   116→/**
   117→ * 타입 문자열 표현
   118→ */
   119→export function typeToString(type: Type): string {
   120→  switch (type.kind) {
   121→    case "primitive":
   122→      return type.type
   123→
   124→    case "array":
   125→      return `array[${typeToString(type.elementType)}]`
   126→
   127→    case "object":
   128→      const props = Array.from(type.properties.entries())
   129→        .map(([k, v]) => `${k}: ${typeToString(v)}`)
   130→        .join(", ")
   131→      return `object{${props}}`
   132→
   133→    case "fn":
   134→      const params = type.paramTypes.map(typeToString).join(", ")
   135→      return `(${params}) -> ${typeToString(type.returnType)}`
   136→
   137→    case "union":
   138→      return type.types.map(typeToString).join(" | ")
   139→
   140→    case "never":
   141→      return "never"
   142→  }
   143→}
   144→
   145→/**
   146→ * 타입 파싱 (문자열 → Type)
   147→ */
   148→export function parseType(typeStr: string): Type {
   149→  typeStr = typeStr.trim()
   150→
   151→  // Primitive types
   152→  if (typeStr === "num") {
   153→    return { kind: "primitive", type: PrimitiveType.NUM }
   154→  }
   155→  if (typeStr === "str") {
   156→    return { kind: "primitive", type: PrimitiveType.STR }
   157→  }
   158→  if (typeStr === "bool") {
   159→    return { kind: "primitive", type: PrimitiveType.BOOL }
   160→  }
   161→  if (typeStr === "null") {
   162→    return { kind: "primitive", type: PrimitiveType.NULL }
   163→  }
   164→
   165→  // Array types
   166→  if (typeStr.startsWith("array[") && typeStr.endsWith("]")) {
   167→    const elementTypeStr = typeStr.substring(6, typeStr.length - 1)
   168→    return {
   169→      kind: "array",
   170→      elementType: parseType(elementTypeStr),
   171→    }
   172→  }
   173→
   174→  // Union types
   175→  if (typeStr.includes(" | ")) {
   176→    const types = typeStr.split(" | ").map((t) => parseType(t.trim()))
   177→    return { kind: "union", types }
   178→  }
   179→
   180→  // Default to unknown
   181→  return { kind: "primitive", type: PrimitiveType.UNKNOWN }
   182→}
   183→
   184→/**
   185→ * 연산 결과 타입 결정
   186→ */
   187→export function getOperationResultType(
   188→  op: string,
   189→  leftType: Type,
   190→  rightType: Type
   191→): Type {
   192→  // Primitive operations
   193→  if (
   194→    leftType.kind === "primitive" &&
   195→    rightType.kind === "primitive"
   196→  ) {
   197→    const left = leftType.type
   198→    const right = rightType.type
   199→
   200→    // Numeric operations
   201→    if (op === "Add") {
   202→      if (left === PrimitiveType.NUM && right === PrimitiveType.NUM) {
   203→        return { kind: "primitive", type: PrimitiveType.NUM }
   204→      }
   205→      // String concatenation
   206→      if (left === PrimitiveType.STR || right === PrimitiveType.STR) {
   207→        return { kind: "primitive", type: PrimitiveType.STR }
   208→      }
   209→    }
   210→
   211→    if (
   212→      (op === "Sub" || op === "Mul" || op === "Div" || op === "Mod") &&
   213→      left === PrimitiveType.NUM &&
   214→      right === PrimitiveType.NUM
   215→    ) {
   216→      return { kind: "primitive", type: PrimitiveType.NUM }
   217→    }
   218→
   219→    // Comparison operations
   220→    if (
   221→      op === "Eq" ||
   222→      op === "Neq" ||
   223→      op === "Lt" ||
   224→      op === "Gt" ||
   225→      op === "Lte" ||
   226→      op === "Gte"
   227→    ) {
   228→      return { kind: "primitive", type: PrimitiveType.BOOL }
   229→    }
   230→
   231→    // Logical operations
   232→    if (
   233→      (op === "And" || op === "Or") &&
   234→      left === PrimitiveType.BOOL &&
   235→      right === PrimitiveType.BOOL
   236→    ) {
   237→      return { kind: "primitive", type: PrimitiveType.BOOL }
   238→    }
   239→  }
   240→
   241→  // Array operations
   242→  if (op === "Add" && leftType.kind === "array" && rightType.kind === "array") {
   243→    // Array concatenation results in array
   244→    return leftType
   245→  }
   246→
   247→  return { kind: "primitive", type: PrimitiveType.UNKNOWN }
   248→}
   249→
   250→/**
   251→ * 타입 좁혀짐 (Type Narrowing)
   252→ */
   253→export function narrowType(type: Type, condition: Type): Type {
   254→  // Union 타입에서 일부만 선택
   255→  if (type.kind === "union") {
   256→    for (const t of type.types) {
   257→      if (typesCompatible(t, condition)) {
   258→        return t
   259→      }
   260→    }
   261→  }
   262→
   263→  return type
   264→}
   265→
   266→/**
   267→ * 타입 확대 (Type Widening)
   268→ */
   269→export function widenType(...types: Type[]): Type {
   270→  if (types.length === 0) {
   271→    return { kind: "primitive", type: PrimitiveType.UNKNOWN }
   272→  }
   273→
   274→  if (types.length === 1) {
   275→    return types[0]
   276→  }
   277→
   278→  // 여러 타입을 Union으로 결합
   279→  const uniqueTypes = types.filter(
   280→    (t, i, arr) =>
   281→      arr.findIndex((u) => JSON.stringify(u) === JSON.stringify(t)) === i
   282→  )
   283→
   284→  if (uniqueTypes.length === 1) {
   285→    return uniqueTypes[0]
   286→  }
   287→
   288→  return { kind: "union", types: uniqueTypes }
   289→}
   290→
   291→/**
   292→ * 타입 추론 기본 규칙
   293→ */
   294→export function inferTypeFromValue(value: any): Type {
   295→  if (value === null || value === undefined) {
   296→    return { kind: "primitive", type: PrimitiveType.NULL }
   297→  }
   298→
   299→  switch (typeof value) {
   300→    case "number":
   301→      return { kind: "primitive", type: PrimitiveType.NUM }
   302→    case "string":
   303→      return { kind: "primitive", type: PrimitiveType.STR }
   304→    case "boolean":
   305→      return { kind: "primitive", type: PrimitiveType.BOOL }
   306→    default:
   307→      return { kind: "primitive", type: PrimitiveType.UNKNOWN }
   308→  }
   309→}
   310→
   311→/**
   312→ * 함수 타입 생성
   313→ */
   314→export function createFunctionType(
   315→  paramTypes: Type[],
   316→  returnType: Type
   317→): Type {
   318→  return {
   319→    kind: "fn",
   320→    paramTypes,
   321→    returnType,
   322→  }
   323→}
   324→
   325→/**
   326→ * 객체 타입 생성
   327→ */
   328→export function createObjectType(
   329→  properties: Map<string, Type>
   330→): Type {
   331→  return {
   332→    kind: "object",
   333→    properties,
   334→  }
   335→}
   336→
   337→/**
   338→ * 배열 타입 생성
   339→ */
   340→export function createArrayType(elementType: Type): Type {
   341→  return {
   342→    kind: "array",
   343→    elementType,
   344→  }
   345→}
   346→
   347→/**
   348→ * 기본 타입 미리 정의
   349→ */
   350→export const BUILTIN_TYPES = {
   351→  NUM: { kind: "primitive" as const, type: PrimitiveType.NUM },
   352→  STR: { kind: "primitive" as const, type: PrimitiveType.STR },
   353→  BOOL: { kind: "primitive" as const, type: PrimitiveType.BOOL },
   354→  NULL: { kind: "primitive" as const, type: PrimitiveType.NULL },
   355→  UNKNOWN: { kind: "primitive" as const, type: PrimitiveType.UNKNOWN },
   356→  NEVER: { kind: "never" as const },
