     1→// FreeLang v6: AST Node definitions
     2→
     3→// Phase 5.5.3: 파라미터 — 이름 + 선택적 타입 어노테이션
     4→export type Param = { name: string; typeAnnotation?: string };
     5→
     6→export type Expr =
     7→  | { kind: "number"; value: number }
     8→  | { kind: "string"; value: string }
     9→  | { kind: "bool"; value: boolean }
    10→  | { kind: "null" }
    11→  | { kind: "ident"; name: string }
    12→  | { kind: "binary"; op: string; left: Expr; right: Expr }
    13→  | { kind: "unary"; op: string; expr: Expr }
    14→  | { kind: "call"; callee: Expr; args: Expr[] }
    15→  | { kind: "index"; object: Expr; index: Expr }
    16→  | { kind: "member"; object: Expr; property: string }
    17→  | { kind: "assign"; target: Expr; value: Expr }
    18→  | { kind: "array"; elements: Expr[] }
    19→  | { kind: "object"; entries: { key: string; value: Expr }[] }
    20→  | { kind: "fn"; name: string | null; params: Param[]; body: Stmt[] }
    21→  | { kind: "ternary"; cond: Expr; then: Expr; else: Expr }
    22→  | { kind: "if"; cond: Expr; then: Stmt[]; else: Stmt[] }
    23→  | { kind: "match"; subject: Expr; arms: MatchArm[] };
    24→
    25→export type MatchArm = { pattern: Expr | null; guard: Expr | null; body: Stmt[] };
    26→
    27→// Phase 6: Capability 타입
    28→export type CapabilityKind =
    29→  | "read_file"
    30→  | "write_file"
    31→  | "network"
    32→  | "spawn_process"
    33→  | "execute_code"
    34→
    35→export type CapabilityAnnotation =
    36→  | { kind: "allow"; cap: CapabilityKind; arg?: string }
    37→  | { kind: "limit"; resource: "cpu" | "memory" | "io"; value: number }
    38→
    39→export type Stmt =
    40→  | { kind: "expr"; expr: Expr }
    41→  | { kind: "let"; name: string; mutable: boolean; init: Expr | null }
    42→  | { kind: "return"; value: Expr | null }
    43→  | { kind: "if"; cond: Expr; then: Stmt[]; else: Stmt[] | null }
    44→  | { kind: "if-let"; pattern: Expr; value: Expr; body: Stmt[]; else?: Stmt[] }
    45→  | { kind: "while"; cond: Expr; body: Stmt[] }
    46→  | { kind: "while-let"; pattern: Expr; value: Expr; body: Stmt[] }
    47→  | { kind: "for"; name: string; iter: Expr; body: Stmt[] }
    48→  | { kind: "block"; body: Stmt[] }
    49→  | { kind: "break" }
    50→  | { kind: "continue" }
    51→  | { kind: "fn"; name: string; params: Param[]; body: Stmt[]; annotations?: CapabilityAnnotation[] }
    52→  | { kind: "print"; expr: Expr; newline: boolean }
    53→  | { kind: "try"; body: Stmt[]; catchVar: string | null; catchBody: Stmt[]; finallyBody: Stmt[] }
    54→  | { kind: "throw"; expr: Expr }
    55→  | { kind: "struct"; name: string; fields: Array<{ name: string; type: string }> }
    56→  | { kind: "import"; names: string[] | null; path: string; alias: string | null }
    57→  | { kind: "export"; stmt: Stmt }
    58→  | { kind: "multi"; stmts: Stmt[] }
    59→  | { kind: "match"; subject: Expr; arms: MatchArm[] };
    60→
    61→export type Program = { stmts: Stmt[] };
    62→

