     1→// FreeLang v6: Parser (Pratt / Recursive Descent)
     2→
     3→import { Token, TokenType as T } from "./token";
     4→import { Expr, Stmt, Program, MatchArm, Param } from "./ast";
     5→
     6→export function parse(tokens: Token[]): Program {
     7→  let pos = 0;
     8→
     9→  function peek(): Token { return tokens[pos]; }
    10→  function advance(): Token { return tokens[pos++]; }
    11→  function expect(type: T, msg?: string): Token {
    12→    const t = advance();
    13→    if (t.type !== type) throw new Error(msg ?? `Expected ${T[type]}, got ${T[t.type]} '${t.value}' at line ${t.line}`);
    14→    return t;
    15→  }
    16→  function match(type: T): boolean { if (peek().type === type) { advance(); return true; } return false; }
    17→  function at(type: T): boolean { return peek().type === type; }
    18→
    19→  // --- Statements ---
    20→  function parseProgram(): Program {
    21→    const stmts: Stmt[] = [];
    22→    while (!at(T.EOF)) stmts.push(parseStmt());
    23→    return { stmts };
    24→  }
    25→
    26→  function parseStmt(): Stmt {
    27→    while (match(T.Semicolon)) {} // skip stray semicolons
    28→    if (at(T.EOF)) return { kind: "expr", expr: { kind: "null" } };
    29→    if (at(T.Let) || at(T.Const)) return parseLetStmt();
    30→    if (at(T.Fn)) return parseFnStmt();
    31→    if (at(T.Return)) return parseReturn();
    32→    if (at(T.If)) return parseIf();
    33→    if (at(T.While)) return parseWhile();
    34→    if (at(T.For)) return parseFor();
    35→    if (at(T.LBrace)) return parseBlock();
    36→    if (at(T.Print) || at(T.Println)) return parsePrint();
    37→    if (at(T.Break)) { advance(); match(T.Semicolon); return { kind: "break" }; }
    38→    if (at(T.Continue)) { advance(); match(T.Semicolon); return { kind: "continue" }; }
    39→    if (at(T.Try)) return parseTry();
    40→    if (at(T.Throw)) return parseThrow();
    41→    if (at(T.Struct)) return parseStruct();
    42→    if (at(T.Import)) return parseImport();
    43→    if (at(T.Export)) return parseExport();
    44→    if (at(T.Match)) return parseMatch();
    45→    return parseExprStmt();
    46→  }
    47→
    48→  function parseLetStmt(): Stmt {
    49→    const mutable = advance().type === T.Let;
    50→
    51→    // Object destructuring: let {a, b} = expr
    52→    if (at(T.LBrace)) {
    53→      advance();
    54→      const names: string[] = [];
    55→      while (!at(T.RBrace) && !at(T.EOF)) {
    56→        names.push(expect(T.Ident, "Expected destructured name").value);
    57→        match(T.Comma);
    58→      }
    59→      expect(T.RBrace);
    60→      expect(T.Assign, "Expected '=' after destructuring pattern");
    61→      const init = parseExpr();
    62→      match(T.Semicolon);
    63→      const tmp = `__d${pos}`;
    64→      return { kind: "multi", stmts: [
    65→        { kind: "let", name: tmp, mutable: false, init },
    66→        ...names.map(n => ({
    67→          kind: "let" as const, name: n, mutable,
    68→          init: { kind: "member" as const, object: { kind: "ident" as const, name: tmp }, property: n } as Expr,
    69→        }))
    70→      ]};
    71→    }
    72→
    73→    // Array destructuring: let [x, y] = expr
    74→    if (at(T.LBracket)) {
    75→      advance();
    76→      const names: string[] = [];
    77→      while (!at(T.RBracket) && !at(T.EOF)) {
    78→        names.push(expect(T.Ident, "Expected destructured name").value);
    79→        match(T.Comma);
    80→      }
    81→      expect(T.RBracket);
    82→      expect(T.Assign, "Expected '=' after destructuring pattern");
    83→      const init = parseExpr();
    84→      match(T.Semicolon);
    85→      const tmp = `__d${pos}`;
    86→      return { kind: "multi", stmts: [
    87→        { kind: "let", name: tmp, mutable: false, init },
    88→        ...names.map((n, i) => ({
    89→          kind: "let" as const, name: n, mutable,
    90→          init: { kind: "index" as const, object: { kind: "ident" as const, name: tmp }, index: { kind: "number" as const, value: i } as Expr } as Expr,
    91→        }))
    92→      ]};
    93→    }
    94→
    95→    const name = expect(T.Ident, "Expected variable name").value;
    96→    let init: Expr | null = null;
    97→    if (match(T.Assign)) init = parseExpr();
    98→    match(T.Semicolon);
    99→    return { kind: "let", name, mutable, init };
   100→  }
   101→
   102→  function parseFnStmt(): Stmt {
   103→    advance(); // fn
   104→    const name = expect(T.Ident, "Expected function name").value;
   105→    expect(T.LParen);
   106→    const params = parseParams();
   107→    expect(T.RParen);
   108→    // Phase 6: Parse capability annotations [allow(...), limit(...)]
   109→    const annotations = parseAnnotations();
   110→    // Skip return type annotation if present: -> Type
   111→    if (match(T.Arrow)) {
   112→      // Skip the return type - consume tokens until we hit opening brace
   113→      let depth = 0;
   114→      while (!at(T.LBrace) && !at(T.EOF)) {
   115→        const t = advance();
   116→        if (t.type === T.LBracket) depth++;
   117→        if (t.type === T.RBracket) depth--;
   118→        if (depth < 0) break;
   119→      }
   120→    }
   121→    expect(T.LBrace);
   122→    const body = parseBody();
   123→    expect(T.RBrace);
   124→    return { kind: "fn", name, params, body, annotations };
   125→  }
   126→
   127→  function parseReturn(): Stmt {
   128→    advance(); // return
   129→    let value: Expr | null = null;
   130→    if (!at(T.Semicolon) && !at(T.RBrace) && !at(T.EOF)) value = parseExpr();
   131→    match(T.Semicolon);
   132→    return { kind: "return", value };
   133→  }
   134→
   135→  function parseIf(): Stmt {
   136→    advance(); // if
   137→
   138→    // Check for if let pattern
   139→    if (at(T.Let)) {
   140→      return parseIfLet();
   141→    }
   142→
   143→    const cond = parseExpr();
   144→    expect(T.LBrace);
   145→    const then = parseBody();
   146→    expect(T.RBrace);
   147→    let else_: Stmt[] | null = null;
   148→    if (match(T.Else)) {
   149→      if (at(T.If)) {
   150→        else_ = [parseIf()];
   151→      } else {
   152→        expect(T.LBrace);
   153→        else_ = parseBody();
   154→        expect(T.RBrace);
   155→      }
   156→    }
   157→    return { kind: "if", cond, then, else: else_ };
   158→  }
   159→
   160→  function parseIfLet(): Stmt {
   161→    advance(); // let
   162→    const pattern = parseOr(); // Use parseOr to avoid consuming the = operator
   163→    expect(T.Assign);
   164→    const value = parseOr(); // Use parseOr for consistency
   165→    expect(T.LBrace);
   166→    const body = parseBody();
   167→    expect(T.RBrace);
   168→
   169→    let else_: Stmt[] | undefined;
   170→    if (match(T.Else)) {
   171→      if (at(T.LBrace)) {
   172→        expect(T.LBrace);
   173→        else_ = parseBody();
   174→        expect(T.RBrace);
   175→      } else if (at(T.If)) {
   176→        // else if pattern
   177→        else_ = [parseIf()];
   178→      }
   179→    }
   180→
   181→    return { kind: "if-let", pattern, value, body, else: else_ };
   182→  }
   183→
   184→  /**
   185→   * [v3.1] Parse if as an expression
   186→   *
   187→   * Supports: let x = if condition { value1 } else { value2 };
   188→   *
   189→   * Key difference from parseIf():
   190→   * - Must have else clause (to ensure all paths return a value)
   191→   * - Body can contain expressions (parsed as statements with implicit return)
   192→   * - Result is an Expr, not a Stmt
   193→   */
   194→  function parseIfExpr(): Expr {
   195→    advance(); // if
   196→    const cond = parseExpr();
   197→    expect(T.LBrace);
   198→    const then = parseBody();
   199→    expect(T.RBrace);
   200→
   201→    let else_: Stmt[];
   202→    if (match(T.Else)) {
   203→      if (at(T.If)) {
   204→        // else if: recursively parse as if expression
   205→        else_ = [{ kind: "expr", expr: parseIfExpr() }];
   206→      } else {
   207→        expect(T.LBrace);
   208→        else_ = parseBody();
   209→        expect(T.RBrace);
   210→      }
   211→    } else {
   212→      throw new Error("If expression must have else clause");
   213→    }
   214→
   215→    // Return as an Expr node with kind "if"
   216→    return { kind: "if", cond, then, else: else_ };
   217→  }
   218→
   219→  /**
   220→   * [v3.4] Parse match as an expression
   221→   *
   222→   * Supports: let x = match value { ... };
   223→   * Returns an Expr with kind "match"
   224→   */
   225→  function parseMatchExpr(): Expr {
   226→    advance(); // match
   227→    const subject = parseExpr();
   228→    expect(T.LBrace);
   229→    const arms: MatchArm[] = [];
   230→
   231→    while (!at(T.RBrace) && !at(T.EOF)) {
   232→      let pattern: Expr | null = null;
   233→      if (at(T.Ident) && peek().value === "_") {
   234→        advance(); // _
   235→      } else {
   236→        pattern = parseExpr();
   237→      }
   238→
   239→      // Parse optional guard clause: if condition
   240→      let guard: Expr | null = null;
   241→      if (match(T.If)) {
   242→        guard = parseExpr();
   243→      }
   244→
   245→      expect(T.FatArrow, "Expected '=>' in match arm");
   246→
   247→      // Parse body: can be expr or block
   248→      let body: Stmt[];
   249→      if (at(T.LBrace)) {
   250→        expect(T.LBrace);
   251→        body = parseBody();
   252→        expect(T.RBrace);
   253→      } else {
   254→        // Single expression as body
   255→        const expr = parseExpr();
   256→        body = [{ kind: "expr", expr }];
   257→      }
   258→
   259→      arms.push({ pattern, guard, body });
   260→      match(T.Comma);
   261→    }
   262→
   263→    expect(T.RBrace);
   264→    return { kind: "match", subject, arms } as any;
   265→  }
   266→
   267→  function parseWhile(): Stmt {
   268→    advance(); // while
   269→
   270→    // Check for while let pattern
   271→    if (at(T.Let)) {
   272→      return parseWhileLet();
   273→    }
   274→
   275→    const useParen = match(T.LParen);
   276→    const cond = parseExpr();
   277→    if (useParen) expect(T.RParen);
   278→    expect(T.LBrace);
   279→    const body = parseBody();
   280→    expect(T.RBrace);
   281→    return { kind: "while", cond, body };
   282→  }
   283→
   284→  function parseWhileLet(): Stmt {
   285→    advance(); // let
   286→    const pattern = parseOr(); // Use parseOr to avoid consuming the = operator
   287→    expect(T.Assign);
   288→    const value = parseOr(); // Use parseOr for consistency
   289→    expect(T.LBrace);
   290→    const body = parseBody();
   291→    expect(T.RBrace);
   292→
   293→    return { kind: "while-let", pattern, value, body };
   294→  }
   295→
   296→  function parseFor(): Stmt {
   297→    advance(); // for
   298→    const name = expect(T.Ident, "Expected loop variable").value;
   299→    expect(T.In, "Expected 'in'");
   300→    const iter = parseExpr();
   301→    expect(T.LBrace);
   302→    const body = parseBody();
   303→    expect(T.RBrace);
   304→    return { kind: "for", name, iter, body };
   305→  }
   306→
   307→  function parseBlock(): Stmt {
   308→    expect(T.LBrace);
   309→    const body = parseBody();
   310→    expect(T.RBrace);
   311→    return { kind: "block", body };
   312→  }
   313→
   314→  function parsePrint(): Stmt {
   315→    const newline = advance().type === T.Println;
   316→    expect(T.LParen);
   317→    const expr = parseExpr();
   318→    expect(T.RParen);
   319→    match(T.Semicolon);
   320→    return { kind: "print", expr, newline };
   321→  }
   322→
   323→  function parseTry(): Stmt {
   324→    advance(); // try
   325→    expect(T.LBrace);
   326→    const body = parseBody();
   327→    expect(T.RBrace);
   328→    let catchVar: string | null = null;
   329→    let catchBody: Stmt[] = [];
   330→    let finallyBody: Stmt[] = [];
   331→    if (match(T.Catch)) {
   332→      if (match(T.LParen)) {
   333→        catchVar = expect(T.Ident, "Expected catch variable").value;
   334→        expect(T.RParen);
   335→      }
   336→      expect(T.LBrace);
   337→      catchBody = parseBody();
   338→      expect(T.RBrace);
   339→    }
   340→    if (match(T.Finally)) {
   341→      expect(T.LBrace);
   342→      finallyBody = parseBody();
   343→      expect(T.RBrace);
   344→    }
   345→    return { kind: "try", body, catchVar, catchBody, finallyBody };
   346→  }
   347→
   348→  function parseThrow(): Stmt {
   349→    advance(); // throw
   350→    const expr = parseExpr();
   351→    match(T.Semicolon);
   352→    return { kind: "throw", expr };
   353→  }
   354→
   355→  function parseStruct(): Stmt {
   356→    advance(); // struct
   357→    const name = expect(T.Ident).value;
   358→    expect(T.LBrace);
   359→    const fields: Array<{ name: string; type: string }> = [];
   360→    while (!at(T.RBrace) && !at(T.EOF)) {
   361→      const fieldName = expect(T.Ident).value;
   362→      // Type annotation: "x: i32" or just "x" defaults to "any"
   363→      let fieldType = "any";
   364→      if (at(T.Colon)) {
   365→        advance();
   366→        fieldType = expect(T.Ident).value;
   367→      }
   368→      fields.push({ name: fieldName, type: fieldType });
   369→      match(T.Comma);
   370→    }
   371→    expect(T.RBrace);
   372→    return { kind: "struct", name, fields };
   373→  }
   374→
   375→  function parseImport(): Stmt {
   376→    advance(); // import
   377→    if (at(T.LBrace)) {
   378→      // import { name1, name2 } from "path"
   379→      advance(); // {
   380→      const names: string[] = [];
   381→      while (!at(T.RBrace) && !at(T.EOF)) {
   382→        names.push(expect(T.Ident, "Expected import name").value);
   383→        match(T.Comma);
   384→      }
   385→      expect(T.RBrace);
   386→      expect(T.From, "Expected 'from'");
   387→      const p = expect(T.String, "Expected module path").value;
   388→      match(T.Semicolon);
   389→      return { kind: "import", names, path: p, alias: null };
   390→    } else {
   391→      // import "path" or import "path" as Alias
   392→      const p = expect(T.String, "Expected module path").value;
   393→      let alias: string | null = null;
   394→      if (match(T.As)) alias = expect(T.Ident, "Expected alias name").value;
   395→      match(T.Semicolon);
   396→      return { kind: "import", names: null, path: p, alias };
   397→    }
   398→  }
   399→
   400→  function parseExport(): Stmt {
   401→    advance(); // export
   402→    if (at(T.Fn)) return { kind: "export", stmt: parseFnStmt() };
   403→    if (at(T.Let) || at(T.Const)) return { kind: "export", stmt: parseLetStmt() };
   404→    throw new Error(`Expected fn or let after export at line ${peek().line}`);
   405→  }
   406→
   407→  function parseMatch(): Stmt {
   408→    advance(); // match
   409→    const subject = parseExpr();
   410→    expect(T.LBrace);
   411→    const arms: MatchArm[] = [];
   412→    while (!at(T.RBrace) && !at(T.EOF)) {
   413→      let pattern: Expr | null = null;
   414→      if (at(T.Ident) && peek().value === "_") {
   415→        advance(); // _
   416→      } else {
   417→        pattern = parseExpr();
   418→      }
   419→
   420→      // Parse optional guard clause: if condition
   421→      let guard: Expr | null = null;
   422→      if (match(T.If)) {
   423→        guard = parseExpr();
   424→      }
   425→
   426→      expect(T.FatArrow, "Expected '=>' in match arm");
   427→      let body: Stmt[];
   428→      if (at(T.LBrace)) {
   429→        expect(T.LBrace);
   430→        body = parseBody();
   431→        expect(T.RBrace);
   432→      } else {
   433→        body = [parseStmt()];
   434→      }
   435→      arms.push({ pattern, guard, body });
   436→      match(T.Comma);
   437→    }
   438→    expect(T.RBrace);
   439→    return { kind: "match", subject, arms };
   440→  }
   441→
   442→  function parseExprStmt(): Stmt {
   443→    const expr = parseExpr();
   444→    match(T.Semicolon);
   445→    return { kind: "expr", expr };
   446→  }
   447→
   448→  // --- Expressions (Pratt) ---
   449→  function parseExpr(): Expr { return parseAssign(); }
   450→
   451→  function parseAssign(): Expr {
   452→    let left = parseOr();
   453→    if (at(T.Assign) || at(T.PlusAssign) || at(T.MinusAssign) || at(T.StarAssign) || at(T.SlashAssign)) {
   454→      const op = advance();
   455→      const right = parseAssign();
   456→      if (op.type === T.Assign) return { kind: "assign", target: left, value: right };
   457→      const binOp = op.value[0]; // +, -, *, /
   458→      return { kind: "assign", target: left, value: { kind: "binary", op: binOp, left, right } };
   459→    }
   460→    return left;
   461→  }
   462→
   463→  function parseOr(): Expr {
   464→    let left = parseAnd();
   465→    while (match(T.Or)) left = { kind: "binary", op: "||", left, right: parseAnd() };
   466→    return left;
   467→  }
   468→
   469→  function parseAnd(): Expr {
   470→    let left = parseEquality();
   471→    while (match(T.And)) left = { kind: "binary", op: "&&", left, right: parseEquality() };
   472→    return left;
   473→  }
   474→
   475→  function parseEquality(): Expr {
   476→    let left = parseComparison();
   477→    while (at(T.Eq) || at(T.Neq)) {
   478→      const op = advance().value;
   479→      left = { kind: "binary", op, left, right: parseComparison() };
   480→    }
   481→    return left;
   482→  }
   483→
   484→  function parseComparison(): Expr {
   485→    let left = parseAddition();
   486→    while (at(T.Lt) || at(T.Gt) || at(T.Lte) || at(T.Gte)) {
   487→      const op = advance().value;
   488→      left = { kind: "binary", op, left, right: parseAddition() };
   489→    }
   490→    return left;
   491→  }
   492→
   493→  function parseAddition(): Expr {
   494→    let left = parseMultiplication();
   495→    while (at(T.Plus) || at(T.Minus)) {
   496→      const op = advance().value;
   497→      left = { kind: "binary", op, left, right: parseMultiplication() };
   498→    }
   499→    return left;
   500→  }
   501→
   502→  function parseMultiplication(): Expr {
   503→    let left = parseUnary();
   504→    while (at(T.Star) || at(T.Slash) || at(T.Percent)) {
   505→      const op = advance().value;
   506→      left = { kind: "binary", op, left, right: parseUnary() };
   507→    }
   508→    return left;
   509→  }
   510→
   511→  function parseUnary(): Expr {
   512→    // Handle unary operators: -, !, &, *
   513→    if (at(T.Minus) || at(T.Not) || at(T.Ampersand) || at(T.Star)) {
   514→      const op = advance().value;
   515→      return { kind: "unary", op, expr: parseUnary() };
   516→    }
   517→    return parsePostfix();
   518→  }
   519→
   520→  function parsePostfix(): Expr {
   521→    let expr = parsePrimary();
   522→    while (true) {
   523→      if (match(T.LParen)) {
   524→        const args: Expr[] = [];
   525→        while (!at(T.RParen) && !at(T.EOF)) {
   526→          args.push(parseExpr());
   527→          match(T.Comma);
   528→        }
   529→        expect(T.RParen);
   530→        expr = { kind: "call", callee: expr, args };
   531→      } else if (match(T.LBracket)) {
   532→        const index = parseExpr();
   533→        expect(T.RBracket);
   534→        expr = { kind: "index", object: expr, index };
   535→      } else if (match(T.Dot)) {
   536→        const prop = expect(T.Ident, "Expected property name").value;
   537→        expr = { kind: "member", object: expr, property: prop };
   538→      } else break;
   539→    }
   540→    return expr;
   541→  }
   542→
   543→  function parsePrimary(): Expr {
   544→    const t = peek();
   545→    switch (t.type) {
   546→      case T.Number: advance(); return { kind: "number", value: Number(t.value) };
   547→      case T.String: advance(); return { kind: "string", value: t.value };
   548→      case T.Bool: advance(); return { kind: "bool", value: t.value === "true" };
   549→      case T.Null: advance(); return { kind: "null" };
   550→      case T.Ident: {
   551→        advance();
   552→        // Single-param arrow: x => expr
   553→        if (at(T.FatArrow)) {
   554→          advance();
   555→          // Phase 5.5.3: Param 객체로 변환
   556→          const arrowParam: Param = { name: t.value };
   557→          if (at(T.LBrace)) {
   558→            expect(T.LBrace);
   559→            const body = parseBody();
   560→            expect(T.RBrace);
   561→            return { kind: "fn", name: null, params: [arrowParam], body };
   562→          }
   563→          const expr = parseAssign();
   564→          return { kind: "fn", name: null, params: [arrowParam], body: [{ kind: "return", value: expr }] };
   565→        }
   566→        return { kind: "ident", name: t.value };
   567→      }
   568→      case T.LParen: {
   569→        // Try arrow function: (params) => body
   570→        const savedPos = pos;
   571→        advance(); // (
   572→
   573→        // Check for empty parens arrow: () => ...
   574→        if (at(T.RParen)) {
   575→          const rp = pos;
   576→          advance(); // )
   577→          if (at(T.FatArrow)) {
   578→            advance(); // =>
   579→            return parseArrowBody([]);
   580→          }
   581→          // Not arrow, backtrack
   582→          pos = savedPos;
   583→          advance();
   584→          const expr = parseExpr();
   585→          expect(T.RParen);
   586→          return expr;
   587→        }
   588→
   589→        // Try parsing as ident list for arrow function
   590→        let isArrow = true;
   591→        const params: Param[] = [];  // Phase 5.5.3: Param[]로 변경
   592→        const tryPos = pos;
   593→        while (!at(T.RParen) && !at(T.EOF)) {
   594→          if (!at(T.Ident)) { isArrow = false; break; }
   595→          params.push({ name: advance().value });  // Param 객체로
   596→          if (!at(T.RParen)) {
   597→            if (!match(T.Comma)) { isArrow = false; break; }
   598→          }
   599→        }
   600→        if (isArrow && at(T.RParen)) {
   601→          advance(); // )
   602→          if (at(T.FatArrow)) {
   603→            advance(); // =>
   604→            return parseArrowBody(params);
   605→          }
   606→        }
   607→
   608→        // Not arrow, backtrack and parse as grouped expression
   609→        pos = savedPos;
   610→        advance(); // (
   611→        const expr = parseExpr();
   612→        expect(T.RParen);
   613→        return expr;
   614→      }
   615→      case T.LBracket: return parseArrayLiteral();
   616→      case T.LBrace: return parseObjectLiteral();
   617→      case T.Fn: return parseFnExpr();
   618→      case T.If: return parseIfExpr();
   619→      case T.Match: return parseMatchExpr();
   620→      default: throw new Error(`Unexpected token '${t.value}' at line ${t.line}:${t.col}`);
   621→    }
   622→  }
   623→
   624→  function parseArrowBody(params: Param[]): Expr {  // Phase 5.5.3: Param[]
   625→    if (at(T.LBrace)) {
   626→      expect(T.LBrace);
   627→      const body = parseBody();
   628→      expect(T.RBrace);
   629→      return { kind: "fn", name: null, params, body };
   630→    }
   631→    const expr = parseAssign();
   632→    return { kind: "fn", name: null, params, body: [{ kind: "return", value: expr }] };
   633→  }
   634→
   635→  function parseArrayLiteral(): Expr {
   636→    advance(); // [
   637→    const elements: Expr[] = [];
   638→    while (!at(T.RBracket) && !at(T.EOF)) {
   639→      elements.push(parseExpr());
   640→      match(T.Comma);
   641→    }
   642→    expect(T.RBracket);
   643→    return { kind: "array", elements };
   644→  }
   645→
   646→  function parseObjectLiteral(): Expr {
   647→    advance(); // {
   648→    const entries: { key: string; value: Expr }[] = [];
   649→    while (!at(T.RBrace) && !at(T.EOF)) {
   650→      const key = expect(T.Ident, "Expected key").value;
   651→      expect(T.Colon);
   652→      const value = parseExpr();
   653→      entries.push({ key, value });
   654→      match(T.Comma);
   655→    }
   656→    expect(T.RBrace);
   657→    return { kind: "object", entries };
   658→  }
   659→
   660→  function parseFnExpr(): Expr {
   661→    advance(); // fn
   662→    let name: string | null = null;
   663→    if (at(T.Ident)) name = advance().value;
   664→    expect(T.LParen);
   665→    const params = parseParams();
   666→    expect(T.RParen);
   667→    expect(T.LBrace);
   668→    const body = parseBody();
   669→    expect(T.RBrace);
   670→    return { kind: "fn", name, params, body };
   671→  }
   672→
   673→  function parseParams(): Param[] {
   674→    const params: Param[] = [];
   675→    while (!at(T.RParen) && !at(T.EOF)) {
   676→      const paramName = expect(T.Ident, "Expected parameter name").value;
   677→      let typeAnnotation: string | undefined;
   678→      // Phase 5.5.3: 타입 어노테이션 수집 (버리지 않고 저장)
   679→      if (match(T.Colon)) {
   680→        const typeParts: string[] = [];
   681→        let depth = 0;
   682→        while (!at(T.Comma) && !at(T.RParen) && !at(T.EOF)) {
   683→          const tok = advance();
   684→          if (tok.type === T.LBracket) depth++;
   685→          if (tok.type === T.RBracket) depth--;
   686→          if (depth < 0) break;
   687→          typeParts.push(tok.value);
   688→        }
   689→        typeAnnotation = typeParts.join("").toLowerCase();
   690→      }
   691→      params.push({ name: paramName, typeAnnotation });
   692→      match(T.Comma);
   693→    }
   694→    return params;
   695→  }
   696→
   697→  // Phase 6: Parse capability annotations [allow(...), limit(...)]
   698→  function parseAnnotations(): any[] {
   699→    if (!at(T.LBracket)) return []
   700→    advance() // [
   701→    const annotations: any[] = []
   702→
   703→    while (!at(T.RBracket) && !at(T.EOF)) {
   704→      const name = expect(T.Ident).value // "allow" or "limit"
   705→
   706→      if (name === "allow") {
   707→        expect(T.LParen)
   708→        const capName = expect(T.Ident).value // read_file, network, etc
   709→        let arg: string | undefined
   710→        if (match(T.LParen)) {
   711→          // allow(read_file("/tmp")) — consume string arg
   712→          arg = expect(T.String).value
   713→          expect(T.RParen)
   714→        }
   715→        expect(T.RParen)
   716→        annotations.push({ kind: "allow", cap: capName, arg })
   717→      } else if (name === "limit") {
   718→        expect(T.LParen)
   719→        while (!at(T.RParen) && !at(T.EOF)) {
   720→          const res = expect(T.Ident).value // cpu, memory, io
   721→          expect(T.Assign)
   722→          const val = Number(expect(T.Number).value)
   723→          annotations.push({ kind: "limit", resource: res, value: val })
   724→          match(T.Comma)
   725→        }
   726→        expect(T.RParen)
   727→      }
   728→
   729→      match(T.Comma)
   730→    }
   731→
   732→    expect(T.RBracket) // ]
   733→    return annotations
   734→  }
   735→
   736→  function parseBody(): Stmt[] {
   737→    const stmts: Stmt[] = [];
   738→    while (!at(T.RBrace) && !at(T.EOF)) stmts.push(parseStmt());
   739→    return stmts;
   740→  }
   741→
   742→  return parseProgram();
   743→}
