    19→/**
    20→ * TypeChecker: AST 기반 정적 타입 검증
    21→ */
    22→export class TypeChecker {
    23→  private env: Map<string, Type> = new Map()
    24→  private functionTypes: Map<string, Type> = new Map()
    25→  private errors: TypeCheckError[] = []
    26→  private currentFunctionReturnTypes: Type[] = []
    27→  private currentCapabilities: Capability[] = []
    28→
    29→  // Phase 6: Built-in 함수 required capability
    30→  private readonly BUILTIN_REQUIRED_CAPABILITIES: Map<string, CapabilityKind> = new Map([
    31→    ["file_read", "read_file"],
    32→    ["file_write", "write_file"],
    33→    ["http_request", "network"],
    34→    ["http_get", "network"],
    35→    ["process_spawn", "spawn_process"],
    36→    ["eval", "execute_code"],
    37→  ])
    38→
    39→  /**
    40→   * 전체 프로그램 타입 검사
    41→   */
    42→  public check(program: Program): TypeCheckResult {
    43→    this.errors = []
    44→    this.env.clear()
    45→    this.functionTypes.clear()
    46→
    47→    // First pass: 함수 정의 수집
    48→    for (const stmt of program.stmts) {
    49→      if (stmt.kind === "fn") {
    50→        this.registerFunctionType(stmt)
    51→      }
    52→    }
    53→
    54→    // Second pass: 함수 본문 및 다른 명령문 검사
    55→    for (const stmt of program.stmts) {
    56→      this.checkStmt(stmt)
    57→    }
