    60→      success: this.errors.length === 0,
    61→      errors: this.errors,
    62→      types: new Map(this.env),
    63→    }
    64→  }
    65→
    66→  /**
    67→   * 수집된 return 타입들로부터 함수의 반환 타입 추론
    68→   */
    69→  private inferReturnType(types: Type[]): Type {
    70→    if (types.length === 0) return BUILTIN_TYPES.UNKNOWN
    71→    const first = types[0]
    72→    if (types.every(t => JSON.stringify(t) === JSON.stringify(first)))
    73→      return first
    74→    return BUILTIN_TYPES.UNKNOWN
    75→  }
    76→
    77→  /**
    78→   * 함수 타입 등록
    79→   */
    80→  private registerFunctionType(stmt: Stmt): void {
