   300→      }
   301→    }
   302→  }
   303→
   304→  /**
   305→   * 표현식 타입 검사
   306→   */
   307→  public checkExpr(expr: Expr): Type {
   308→    switch (expr.kind) {
   309→      case "number":
   310→        return { kind: "primitive", type: PrimitiveType.NUM }
   311→
   312→      case "string":
   313→        return { kind: "primitive", type: PrimitiveType.STR }
   314→
   315→      case "bool":
   316→        return { kind: "primitive", type: PrimitiveType.BOOL }
   317→
   318→      case "null":
   319→        return { kind: "primitive", type: PrimitiveType.NULL }
   320→
   321→      case "ident": {
   322→        const identExpr = expr as any
   323→        const type = this.env.get(identExpr.name)
   324→        if (!type) {
   325→          this.addError(
   326→            `Undefined variable '${identExpr.name}'`,
   327→            undefined,
   328→            undefined
   329→          )
   330→          return BUILTIN_TYPES.UNKNOWN
   331→        }
   332→        return type
   333→      }
   334→
   335→      case "assign": {
   336→        const assignExpr = expr as any
   337→        const valueType = this.checkExpr(assignExpr.value)
   338→
   339→        // target이 ident인 경우 할당
   340→        if (assignExpr.target.kind === "ident") {
   341→          this.env.set(assignExpr.target.name, valueType)
   342→        }
   343→        return valueType
   344→      }
   345→
   346→      case "binary": {
   347→        const binExpr = expr as any
   348→        const leftType = this.checkExpr(binExpr.left)
   349→        const rightType = this.checkExpr(binExpr.right)
   350→
   351→        // 타입 호환성 검사
   352→        const resultType = getOperationResultType(
   353→          binExpr.op,
   354→          leftType,
   355→          rightType
   356→        )
   357→
   358→        // Add 연산 검증
   359→        if (binExpr.op === "+" || binExpr.op === "Add") {
   360→          if (leftType.kind === "primitive" && rightType.kind === "primitive") {
   361→            const left = leftType.type
   362→            const right = rightType.type
   363→
   364→            if (
   365→              !(
   366→                (left === PrimitiveType.NUM && right === PrimitiveType.NUM) ||
   367→                (left === PrimitiveType.STR || right === PrimitiveType.STR) ||
   368→                (left === PrimitiveType.UNKNOWN ||
   369→                  right === PrimitiveType.UNKNOWN)
   370→              )
   371→            ) {
   372→              this.addError(
   373→                `Cannot add ${typeToString(leftType)} and ${typeToString(rightType)}`,
   374→                undefined,
   375→                undefined,
   376→                undefined,
   377→                leftType,
   378→                rightType
   379→              )
   380→            }
   381→          }
   382→        }
   383→
   384→        return resultType
   385→      }
   386→
   387→      case "unary": {
   388→        const unaryExpr = expr as any
   389→        const operandType = this.checkExpr(unaryExpr.expr)
   390→
   391→        if (unaryExpr.op === "!") {
   392→          if (
   393→            operandType.kind !== "primitive" ||
   394→            operandType.type !== PrimitiveType.BOOL
   395→          ) {
   396→            this.addError(
   397→              `Cannot apply ! to ${typeToString(operandType)}`,
   398→              undefined,
   399→              undefined
   400→            )
   401→          }
   402→          return BUILTIN_TYPES.BOOL
   403→        }
   404→
   405→        if (unaryExpr.op === "-") {
   406→          if (
   407→            operandType.kind !== "primitive" ||
   408→            operandType.type !== PrimitiveType.NUM
   409→          ) {
   410→            this.addError(
   411→              `Cannot negate ${typeToString(operandType)}`,
   412→              undefined,
   413→              undefined
   414→            )
   415→          }
   416→          return BUILTIN_TYPES.NUM
   417→        }
   418→
   419→        return operandType
   420→      }
   421→
   422→      case "call": {
   423→        const callExpr = expr as any
   424→
   425→        // callee에서 함수 이름 추출
   426→        let fnName = ""
   427→        if (callExpr.callee.kind === "ident") {
   428→          fnName = callExpr.callee.name
   429→        }
   430→
   431→        // Phase 6: Built-in 함수 required capability 검사
   432→        const builtinRequired = this.BUILTIN_REQUIRED_CAPABILITIES.get(fnName)
   433→        if (builtinRequired) {
   434→          const callerHas = this.currentCapabilities.some(c => c.cap === builtinRequired)
   435→          if (!callerHas) {
   436→            this.addError(
   437→              `'${fnName}' requires capability '${builtinRequired}', not declared`,
   438→              undefined,
   439→              undefined
   440→            )
   441→          }
   442→        }
   443→
   444→        const fnType = this.functionTypes.get(fnName)
   445→
   446→        if (!fnType) {
   447→          this.addError(
   448→            `Undefined function '${fnName}'`,
   449→            undefined,
   450→            undefined
   451→          )
   452→          return BUILTIN_TYPES.UNKNOWN
   453→        }
   454→
   455→        if (fnType.kind === "fn") {
   456→          // 인자 개수 확인
   457→          if ((callExpr.args || []).length !== fnType.paramTypes.length) {
   458→            this.addError(
   459→              `Function '${fnName}' expects ${fnType.paramTypes.length} arguments, got ${(callExpr.args || []).length}`,
   460→              undefined,
   461→              undefined
   462→            )
   463→          }
   464→
   465→          // 인자 타입 검사
   466→          for (let i = 0; i < (callExpr.args || []).length; i++) {
   467→            const argType = this.checkExpr(callExpr.args[i])
   468→            const paramType = fnType.paramTypes[i] || BUILTIN_TYPES.UNKNOWN
   469→
   470→            if (!typesCompatible(argType, paramType)) {
   471→              this.addError(
   472→                `Argument ${i} of '${fnName}': expected ${typeToString(paramType)}, got ${typeToString(argType)}`,
   473→                undefined,
   474→                undefined,
   475→                undefined,
   476→                paramType,
   477→                argType
   478→              )
   479→            }
   480→          }
   481→
   482→          // Phase 6: Capability Propagation 검증
   483→          // Strict: callee.capabilities ⊆ caller.capabilities
   484→          if (fnType.capabilities && fnType.capabilities.length > 0) {
   485→            for (const required of fnType.capabilities) {
   486→              const callerHas = this.currentCapabilities.some(
   487→                c => c.cap === required.cap && this.capabilityCovers(c, required)
   488→              )
   489→              if (!callerHas) {
   490→                this.addError(
   491→                  `Call to '${fnName}' requires capability '${required.cap}' ` +
   492→                  `${required.arg ? `(${required.arg})` : ""}, ` +
   493→                  `but caller does not declare it`,
   494→                  undefined,
   495→                  undefined
   496→                )
   497→              }
   498→            }
   499→          }
   500→
   501→          return fnType.returnType
   502→        }
   503→
   504→        return BUILTIN_TYPES.UNKNOWN
   505→      }
   506→
   507→      case "array": {
   508→        const arrayExpr = expr as any
   509→        if ((arrayExpr.elements || []).length === 0) {
   510→          return {
   511→            kind: "array",
   512→            elementType: BUILTIN_TYPES.UNKNOWN,
   513→          }
   514→        }
   515→
   516→        const elementTypes = (arrayExpr.elements || []).map((e: any) =>
   517→          this.checkExpr(e)
   518→        )
   519→
   520→        // 모든 요소 타입이 같은지 확인
   521→        const firstType = elementTypes[0]
   522→        for (let i = 1; i < elementTypes.length; i++) {
   523→          if (!typesCompatible(elementTypes[i], firstType)) {
   524→            this.addError(
   525→              `Array elements have inconsistent types: ${typeToString(firstType)} and ${typeToString(elementTypes[i])}`,
   526→              undefined,
   527→              undefined
   528→            )
   529→          }
   530→        }
   531→
   532→        return {
   533→          kind: "array",
   534→          elementType: firstType,
   535→        }
   536→      }
   537→
   538→      case "index": {
   539→        const indexExpr = expr as any
   540→        const objectType = this.checkExpr(indexExpr.object)
   541→        this.checkExpr(indexExpr.index)
   542→
   543→        if (objectType.kind === "array") {
   544→          return objectType.elementType
   545→        }
   546→        return BUILTIN_TYPES.UNKNOWN
   547→      }
   548→
   549→      case "member": {
   550→        const memberExpr = expr as any
   551→        const objectType = this.checkExpr(memberExpr.object)
   552→
   553→        if (objectType.kind === "object") {
   554→          const propType = objectType.properties.get(memberExpr.property)
   555→          return propType || BUILTIN_TYPES.UNKNOWN
   556→        }
   557→        return BUILTIN_TYPES.UNKNOWN
   558→      }
   559→
   560→      case "object": {
   561→        const objExpr = expr as any
   562→        const properties = new Map<string, Type>()
   563→
   564→        for (const entry of objExpr.entries || []) {
   565→          properties.set(entry.key, this.checkExpr(entry.value))
   566→        }
   567→
   568→        return {
   569→          kind: "object",
   570→          properties,
   571→        }
   572→      }
   573→
   574→      case "fn": {
   575→        const fnExpr = expr as any
   576→        const savedEnv = new Map(this.env)
   577→        const savedReturnTypes = this.currentFunctionReturnTypes
   578→
   579→        this.currentFunctionReturnTypes = []
   580→
   581→        // Phase 5.5.3: fn 표현식 파라미터도 어노테이션 적용
   582→        for (const param of fnExpr.params || []) {
   583→          this.env.set(param.name, parseType(param.typeAnnotation ?? "unknown"))
   584→        }
   585→
   586→        // 함수 본문 검사
   587→        for (const stmt of fnExpr.body || []) {
   588→          this.checkStmt(stmt)
   589→        }
   590→
   591→        const inferredReturn = this.inferReturnType(
   592→          this.currentFunctionReturnTypes
   593→        )
   594→        // Phase 5.5.3: fn 표현식도 어노테이션 기반 paramTypes
   595→        const paramTypes: Type[] = (fnExpr.params || []).map((p: any) =>
   596→          parseType(p.typeAnnotation ?? "unknown")
   597→        )
   598→
   599→        this.currentFunctionReturnTypes = savedReturnTypes
   600→        this.env = savedEnv
   601→
   602→        return {
   603→          kind: "fn",
   604→          paramTypes,
   605→          returnType: inferredReturn,
   606→        }
   607→      }
   608→
   609→      case "ternary": {
   610→        const ternaryExpr = expr as any
   611→        this.checkExpr(ternaryExpr.cond)
   612→        const thenType = this.checkExpr(ternaryExpr.then)
   613→        const elseType = this.checkExpr(ternaryExpr.else)
   614→
   615→        // then과 else 타입이 호환 가능해야 함
   616→        if (!typesCompatible(thenType, elseType)) {
   617→          this.addError(
   618→            `Ternary branch types incompatible: ${typeToString(thenType)} vs ${typeToString(elseType)}`,
   619→            undefined,
   620→            undefined
   621→          )
   622→        }
   623→
   624→        return thenType
   625→      }
   626→
   627→      case "if": {
   628→        const ifExpr = expr as any
   629→        this.checkExpr(ifExpr.cond)
   630→        for (const s of ifExpr.then || []) {
   631→          this.checkStmt(s)
   632→        }
   633→        for (const s of ifExpr.else || []) {
   634→          this.checkStmt(s)
   635→        }
   636→        return BUILTIN_TYPES.UNKNOWN
   637→      }
   638→
   639→      case "match": {
   640→        const matchExpr = expr as any
   641→        this.checkExpr(matchExpr.subject)
   642→        for (const arm of matchExpr.arms || []) {
   643→          if (arm.pattern) {
   644→            this.checkExpr(arm.pattern)
   645→          }
   646→          if (arm.guard) {
   647→            this.checkExpr(arm.guard)
   648→          }
   649→          for (const s of arm.body || []) {
   650→            this.checkStmt(s)
   651→          }
   652→        }
   653→        return BUILTIN_TYPES.UNKNOWN
   654→      }
   655→
   656→      default:
   657→        return BUILTIN_TYPES.UNKNOWN
   658→    }
   659→  }
   660→
   661→  /**
   662→   * 오류 추가
   663→   */
   664→  private addError(
   665→    message: string,
   666→    line?: number,
   667→    column?: number,
   668→    variable?: string,
   669→    expected?: Type,
   670→    actual?: Type
   671→  ): void {
   672→    this.errors.push({
   673→      message,
   674→      line,
   675→      column,
   676→      variable,
   677→      expected,
   678→      actual,
   679→    })
   680→  }
   681→
   682→  /**
   683→   * 환경 조회
   684→   */
   685→  public getEnv(): Map<string, Type> {
   686→    return new Map(this.env)
   687→  }
   688→
   689→  /**
   690→   * 함수 타입 조회
   691→   */
   692→  public getFunctionType(name: string): Type | undefined {
   693→    return this.functionTypes.get(name)
   694→  }
   695→
   696→  /**
   697→   * 오류 개수
   698→   */
   699→  public getErrorCount(): number {
   700→    return this.errors.length
   701→  }
   702→
   703→  /**
   704→   * 오류 목록
   705→   */
   706→  public getErrors(): TypeCheckError[] {
   707→    return [...this.errors]
   708→  }
   709→
   710→  /**
   711→   * Phase 6: Capability 헬퍼 함수들
   712→   */
   713→  private capabilityCovers(caller: Capability, callee: Capability): boolean {
   714→    if (caller.cap !== callee.cap) return false
   715→    if (!callee.arg) return true // callee가 경로 무관하면 OK
   716→    if (!caller.arg) return false
   717→
   718→    // Path: /tmp → /tmp/file.txt OK, /tmp → /etc NG
   719→    if (caller.cap === "read_file" || caller.cap === "write_file") {
   720→      return this.pathIsUnder(callee.arg, caller.arg)
   721→    }
   722→
   723→    // Network: api.openai.com → api.openai.com OK, *.openai.com → sub.openai.com OK
   724→    if (caller.cap === "network") {
   725→      return this.hostMatches(callee.arg, caller.arg)
   726→    }
   727→
   728→    return caller.arg === callee.arg
   729→  }
   730→
   731→  private pathIsUnder(target: string, allowedPrefix: string): boolean {
   732→    // ".." 즉시 거부
   733→    if (target.includes("..")) return false
   734→    const normalized = target.replace(/\/+/g, "/").replace(/\/$/, "")
   735→    const prefix = allowedPrefix.replace(/\/+/g, "/").replace(/\/$/, "")
   736→    return normalized === prefix || normalized.startsWith(prefix + "/")
   737→  }
   738→
   739→  private hostMatches(target: string, pattern: string): boolean {
   740→    if (pattern === target) return true
   741→    if (pattern.startsWith("*.")) {
   742→      const base = pattern.slice(2)
   743→      return (
   744→        target.endsWith("." + base) &&
   745→        !target.slice(0, -base.length - 1).includes(".")
   746→      )
   747→    }
   748→    return false
   749→  }
   750→}
   751→

