   116→    // Ident / Keyword
   117→    if (isAlpha(ch)) {
   118→      const start = i;
   119→      while (i < source.length && isAlphaNum(source[i])) i++;
   120→      const word = source.slice(start, i);
   121→      tokens.push({ type: KEYWORDS[word] ?? T.Ident, value: word, line, col });
   122→      col += i - start;
   123→      continue;
   124→    }
   125→
   126→    // Operators & Delimiters
   127→    const startCol = col;
   128→    switch (ch) {
   129→      case "+": tokens.push(source[i+1] === "=" ? (i++, col++, tok(T.PlusAssign, "+=")) : tok(T.Plus, "+")); break;
   130→      case "-": tokens.push(source[i+1] === ">" ? (i++, col++, tok(T.Arrow, "->")) : source[i+1] === "=" ? (i++, col++, tok(T.MinusAssign, "-=")) : tok(T.Minus, "-")); break;
   131→      case "*": tokens.push(source[i+1] === "=" ? (i++, col++, tok(T.StarAssign, "*=")) : tok(T.Star, "*")); break;
   132→      case "/": tokens.push(source[i+1] === "=" ? (i++, col++, tok(T.SlashAssign, "/=")) : tok(T.Slash, "/")); break;
   133→      case "%": tokens.push(tok(T.Percent, "%")); break;
   134→      case "=": tokens.push(source[i+1] === "=" ? (i++, col++, tok(T.Eq, "==")) : source[i+1] === ">" ? (i++, col++, tok(T.FatArrow, "=>")) : tok(T.Assign, "=")); break;
   135→      case "!": tokens.push(source[i+1] === "=" ? (i++, col++, tok(T.Neq, "!=")) : tok(T.Not, "!")); break;
   136→      case "<": tokens.push(source[i+1] === "=" ? (i++, col++, tok(T.Lte, "<=")) : tok(T.Lt, "<")); break;
   137→      case ">": tokens.push(source[i+1] === "=" ? (i++, col++, tok(T.Gte, ">=")) : tok(T.Gt, ">")); break;
   138→      case "&":
   139→        if (source[i+1] === "&") {
   140→          i++; col++; tokens.push(tok(T.And, "&&"));
   141→        } else {
   142→          tokens.push(tok(T.Ampersand, "&"));
   143→        }
   144→        break;
   145→      case "|": if (source[i+1] === "|") { i++; col++; tokens.push(tok(T.Or, "||")); } break;
   146→      case "(": tokens.push(tok(T.LParen, "(")); break;
   147→      case ")": tokens.push(tok(T.RParen, ")")); break;
   148→      case "{": tokens.push(tok(T.LBrace, "{")); break;
   149→      case "}": tokens.push(tok(T.RBrace, "}")); break;
   150→      case "[": tokens.push(tok(T.LBracket, "[")); break;
   151→      case "]": tokens.push(tok(T.RBracket, "]")); break;
   152→      case ",": tokens.push(tok(T.Comma, ",")); break;
   153→      case ";": tokens.push(tok(T.Semicolon, ";")); break;
   154→      case ":": tokens.push(tok(T.Colon, ":")); break;
   155→      case ".": tokens.push(source[i+1] === "." ? (i++, col++, tok(T.DotDot, "..")) : tok(T.Dot, ".")); break;
   156→      default: throw new Error(`Unexpected character '${ch}' at line ${line}:${col}`);
   157→    }
   158→    i++; col++;
   159→
   160→    function tok(type: T, value: string): Token {
   161→      return { type, value, line, col: startCol };
   162→    }
   163→  }
   164→
   165→  tokens.push({ type: T.EOF, value: "", line, col });
   166→  return tokens;
   167→}
   168→
   169→function isDigit(ch: string): boolean { return ch >= "0" && ch <= "9"; }
   170→function isAlpha(ch: string): boolean { return (ch >= "a" && ch <= "z") || (ch >= "A" && ch <= "Z") || ch === "_"; }
   171→function isAlphaNum(ch: string): boolean { return isAlpha(ch) || isDigit(ch); }
